public class InputSanitizer {

    public String sanitizeForHtml(String input) {
        // Replace: & -> &amp;, < -> &lt;, > -> &gt;, " -> &quot;, ' -> &#x27;
        if (input == null) return "";
        return input
            .replace("&", "&amp;")
            .replace("<", "<")
            .replace(">", ">")
            .replace("\"", "&quot;")
            .replace("'", "&#x27;");
    }

    public boolean isSafeForSql(String input) {
        // Return false if input contains SQL injection patterns
        // Check for: single quote, double dash, semicolon, block comments
        if (input == null) return true;
        String lower = input.toLowerCase();
        return !lower.contains("'") &&
               !lower.contains("--") &&
               !lower.contains(";") &&
               !lower.contains("/*");
    }

    public String sanitizeForShell(String input) {
        // Remove shell metacharacters: & | ; $ ` ( ) < > " ' \
        if (input == null) return "";
        return input.replaceAll("[&|;$`()<>\"'\\\\]", "");
    }

    public static void main(String[] args) {
        InputSanitizer sanitizer = new InputSanitizer();

        System.out.println(sanitizer.sanitizeForHtml("<script>alert('xss')</script>"));
        System.out.println(sanitizer.isSafeForSql("admin' OR '1'='1"));
        System.out.println(sanitizer.isSafeForSql("validUsername"));
        System.out.println(sanitizer.sanitizeForShell("ls -la; rm -rf /"));
    }
}

import java.util.regex.*;

public class DataMasker {

    public String maskCreditCard(String cardNumber) {
        // Keep first 4 and last 4 digits, replace middle with ****
        // Input format: 16 digits, may include spaces or dashes
        if (cardNumber == null) return null;
        String digits = cardNumber.replaceAll("[\\s-]", "");
        if (digits.length() != 16) return cardNumber;
        return digits.substring(0, 4) + "-****-****-" + digits.substring(12);
    }

    public String maskEmail(String email) {
        // Mask local part: keep first 2 chars, replace rest before @ with ***
        if (email == null || !email.contains("@")) return email;
        int atIndex = email.indexOf('@');
        String local = email.substring(0, atIndex);
        String domain = email.substring(atIndex);
        if (local.length() <= 2) return "***" + domain;
        return local.substring(0, 2) + "***" + domain;
    }

    public String maskApiKey(String text) {
        // Find patterns matching 'apikey=XXXX...' and mask the key value
        // Replace each occurrence: keep first 4 chars of key, mask the rest with ****
        if (text == null) return null;
        return text.replaceAll(
            "(apikey=)([A-Za-z0-9]{4})([A-Za-z0-9]+)",
            "$1$2****"
        );
    }

    public static void main(String[] args) {
        DataMasker masker = new DataMasker();
        System.out.println(masker.maskCreditCard("4111 1111 1111 1234"));
        System.out.println(masker.maskEmail("alice.smith@example.com"));
        System.out.println(masker.maskApiKey("Request with apikey=AbCd1234XyZ987 attached"));
    }
}

import java.util.*;
import java.util.stream.*;

public class SecurityAuditLogger {

    public enum EventType { LOGIN_SUCCESS, LOGIN_FAILURE, ACCESS_DENIED, DATA_ACCESS, CONFIG_CHANGE }

    public record AuditEvent(long timestampMs, EventType type, String username, String details) {}

    private final List<AuditEvent> events = new ArrayList<>();

    public void log(long timestampMs, EventType type, String username, String details) {
        events.add(new AuditEvent(timestampMs, type, username, details));
    }

    public List<AuditEvent> filterByType(EventType type) {
        return events.stream().filter(e -> e.type() == type).collect(Collectors.toList());
    }

    public List<AuditEvent> filterByTimeRange(long fromMs, long toMs) {
        // Return events where fromMs <= timestamp <= toMs
        return new ArrayList<>();
    }

    public Map<EventType, Long> summarize() {
        // Return count of events per EventType
        return new HashMap<>();
    }

    public static void main(String[] args) {
        SecurityAuditLogger logger = new SecurityAuditLogger();
        logger.log(1000, EventType.LOGIN_SUCCESS, "alice", "Logged in from 10.0.0.1");
        logger.log(2000, EventType.LOGIN_FAILURE, "bob", "Bad credentials");
        logger.log(3000, EventType.ACCESS_DENIED, "bob", "Tried /admin");
        logger.log(4000, EventType.LOGIN_FAILURE, "bob", "Bad credentials again");

        System.out.println("Login failures: " + logger.filterByType(EventType.LOGIN_FAILURE).size());
        System.out.println("Between 1000-3000: " + logger.filterByTimeRange(1000, 3000).size());
        System.out.println("Summary: " + logger.summarize());
    }
}

